class DemocraticCentralismSystem:
    def __init__(self):
        self.hierarchy = {}  # Maps levels to their organs
        self.decision_flow = []  # Tracks decisions as they propagate

    def add_organ(self, level, organ_name):
        if level not in self.hierarchy:
            self.hierarchy[level] = []
        self.hierarchy[level].append(organ_name)

    def make_decision(self, organ, decision):
        self.decision_flow.append(f"Decision '{decision}' made by {organ}")
        for higher_level in range(max(self.hierarchy.keys()), 0, -1):
            if organ in self.hierarchy.get(higher_level, []):
                for lower_organ in self.hierarchy.get(higher_level - 1, []):
                    self.decision_flow.append(f"Decision enforced on {lower_organ}")

# Example usage
system = DemocraticCentralismSystem()
system.add_organ(1, "Central Committee")
system.add_organ(2, "Regional Branch")
system.add_organ(3, "Local Cell")
system.make_decision("Central Committee", "Five-Year Plan Approved")
